.darma-loader-darma-custom-591 {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
   width: 60px;
   aspect-ratio: 1;
   background: linear-gradient(45deg,var(--loader-color, #4f46e5) 50%,#0000 0), linear-gradient(45deg,#0000 50%,var(--loader-color, #4f46e5) 0), linear-gradient(-45deg,var(--loader-color, #4f46e5) 50%,#0000 0), linear-gradient(-45deg,#0000 50%,var(--loader-color, #4f46e5) 0), linear-gradient(var(--loader-color, #4f46e5) 0 0);
   background-size: 50% 50%;
   background-repeat: no-repeat;
   animation: darma-loader-darma-custom-591-l18 1.5s infinite;
}
@keyframes darma-loader-darma-custom-591-l18 {
  0% {background-position:50% 50%,50% 50%,50% 50% ,50% 50%,50% 50%}
25% {background-position:0 100%,100% 0,50% 50% ,50% 50%,50% 50%}
50% {background-position:0 100%,100% 0,100% 100%,0 0 ,50% 50%}
75% {background-position:50% 50%,50% 50%,100% 100%,0 0 ,50% 50%}
100% {background-position:50% 50%,50% 50%,50% 50% ,50% 50%,50% 50%}
}

